package com.bookstore.service;

import com.bookstore.model.Book;
import com.bookstore.repository.BookRepository;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;
import java.util.List;
import java.util.stream.Collectors;

@Service
public class SearchService {
    @Autowired
    private BookRepository bookRepository;

    public List<Book> search(String query, String author, Double maxPrice) {
        List<Book> books = bookRepository.findAll();
        return books.stream()
            .filter(b -> query == null || b.getTitle().toLowerCase().contains(query.toLowerCase()))
            .filter(b -> author == null || b.getAuthor().equalsIgnoreCase(author))
            .filter(b -> maxPrice == null || b.getPrice() <= maxPrice)
            .collect(Collectors.toList());
    }
}

