package com.bookstore.integration;

import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.AutoConfigureMockMvc;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.test.web.servlet.MockMvc;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.get;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;

@SpringBootTest
@AutoConfigureMockMvc
public class SearchIntegrationTest {
    @Autowired
    private MockMvc mockMvc;

    @Test
    void searchByQuery_returnsMatchingBooks() throws Exception {
        mockMvc.perform(get("/api/books/search").param("query", "spring"))
            .andExpect(status().isOk())
            .andExpect(jsonPath("$").isArray());
    }

    @Test
    void searchByAuthor_filtersCorrectly() throws Exception {
        mockMvc.perform(get("/api/books/search").param("author", "Joshua Bloch"))
            .andExpect(status().isOk())
            .andExpect(jsonPath("$").isArray());
    }

    @Test
    void searchWithMaxPrice_filtersCorrectly() throws Exception {
        mockMvc.perform(get("/api/books/search").param("maxPrice", "29.99"))
            .andExpect(status().isOk())
            .andExpect(jsonPath("$").isArray());
    }
}
